downstreamRead.query:
query MarketMutationFirstUpdateRead($marketId: ID!, $catalogId: ID!) {
  market(id: $marketId) {
    id
    name
    handle
    status
    enabled
    catalogs(first: 10) {
      nodes {
        id
        title
        markets(first: 10) {
          nodes {
            id
            name
            handle
            status
            type
          }
        }
      }
    }
    webPresences(first: 10) {
      nodes {
        id
        subfolderSuffix
        markets(first: 10) {
          nodes {
            id
            name
            handle
            status
            type
          }
        }
      }
    }
  }
  catalog(id: $catalogId) {
    id
    title
    status
    ... on MarketCatalog {
      markets(first: 10) {
        nodes {
          id
          name
          handle
          status
          type
        }
      }
    }
  }
}

topLevelRead.query:
query MarketMutationFirstUpdateTopLevelRead(
  $primaryMarketQuery: String!
  $updateMarketQuery: String!
  $otherMarketQuery: String!
  $catalogsFirst: Int!
  $priceListsFirst: Int!
  $webPresencesFirst: Int!
) {
  primaryMarketFromList: markets(first: 1, query: $primaryMarketQuery, sortKey: ID) {
    nodes {
      id
      name
      handle
      status
      type
    }
  }
  updateMarketFromList: markets(first: 1, query: $updateMarketQuery, sortKey: ID) {
    nodes {
      id
      name
      handle
      status
      type
    }
  }
  otherMarketFromList: markets(first: 1, query: $otherMarketQuery, sortKey: ID) {
    nodes {
      id
      name
      handle
      status
      type
    }
  }
  catalogs(first: $catalogsFirst, type: MARKET, sortKey: ID) {
    nodes {
      id
      title
      status
      ... on MarketCatalog {
        markets(first: 5) {
          nodes {
            id
            name
            handle
            status
            type
          }
        }
      }
      priceList {
        id
        name
        currency
      }
    }
  }
  catalogsCount(type: MARKET) {
    count
    precision
  }
  priceLists(first: $priceListsFirst, sortKey: ID) {
    nodes {
      id
      name
      currency
      catalog {
        id
        title
        status
      }
    }
  }
  webPresences(first: $webPresencesFirst) {
    nodes {
      id
      subfolderSuffix
      defaultLocale {
        locale
        name
        primary
        published
      }
      markets(first: 5) {
        nodes {
          id
          name
          handle
          status
          type
        }
      }
    }
  }
}

